      "path": "src/modules/projects/service.js",
      "content": "let projectsStore = [];

async function createProject(name) {
  if (projectsStore.some(project => project.name === name)) {
    const error = new Error('Project already exists');
    error.code = 'DUPLICATE_PROJECT';
    throw error;
  }
  const project = {
    id: generateId(),
    name,
  };
  projectsStore.push(project);
  return project;
}

async function getProjects() {
  return projectsStore;
}

module.exports = {
  createProject,
  getProjects,
};"
