const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.patch('/', async (req, res) => {
  const { comment } = req.body;
  if (!comment) {
    return sendError(res, 400, 'INVALID_COMMENT', 'Comment is required');
  }
  try {
    const updatedComment = await commentsService.updateComment(req.params.projectId, req.params.taskId, comment);
    if (!updatedComment) {
      return sendError(res, 404, 'COMMENT_NOT_FOUND', 'Comment not found');
    }
    res.json({ comment: updatedComment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;"
