      "path": "src/modules/comments/service.js",
      "content": "let commentsStore = [];

async function updateComment(projectId, taskId, comment) {
  const taskComments = commentsStore.filter(c => c.projectId === projectId && c.taskId === taskId);
  if (taskComments.length === 0) {
    return null;
  }
  const updatedComment = { ...taskComments[0], comment };
  commentsStore = commentsStore.map(c => (c.id === taskComments[0].id ? updatedComment : c));
  return updatedComment;
}

module.exports = {
  updateComment,
};"
